73→    // The zknox NTT (DIT) and felt252 NTT (DIF) evaluate the polynomial at
74→    // the same 512 roots of x^512+1, but output them in different permutation
75→    // order due to different twiddle factor conventions. Verify they produce
76→    // the same multiset by comparing sums and sums of squares.
77→    // Convert Zq to felt252 for comparison with zknox felt252 output.
78→    let mut sum_z: felt252 = 0;
