use corelib_imports::bounded_int::{BoundedInt, DivRemHelper, bounded_int_div_rem, upcast};
use corelib_imports::integer::{U128sFromFelt252Result, u128s_from_felt252};
use falcon::zq::{NZ_Q, QConst, Zq};

// Same types as ntt_felt252.cairo
const SHIFT: felt252 = 2305326338167692623066702044767191040;
type U128AsBounded = BoundedInt<0, 340282366920938463463374607431768211455>;
type ShiftedT = BoundedInt<0, 4612212885115823853836039849917814806>;

impl DivRem_U128_QConst of DivRemHelper<U128AsBounded, QConst> {
    type DivT = BoundedInt<0, 27689996494502275487295516920153650>;
    type RemT = Zq;
}

impl DivRem_ShiftedT_QConst of DivRemHelper<ShiftedT, QConst> {
    type DivT = BoundedInt<0, 375312302475044662204901932615982>;
    type RemT = Zq;
}

const FALLBACK: BoundedInt<1, 1> = 1;

#[inline(always)]
fn felt252_as_u128(x: felt252) -> u128 {
    match u128s_from_felt252(x) {
        U128sFromFelt252Result::Narrow(low) => low,
        U128sFromFelt252Result::Wide((_, low)) => low,
    }
}

/// Baseline: just loop overhead + felt252 add (no conversion)
#[test]
fn bench_baseline_512() {
    let x: felt252 = 7777;
    let mut sum: felt252 = 0;
    let mut i: u32 = 0;
    while i != 512 {
        sum = sum + (x + SHIFT);
        i += 1;
    };
    assert!(sum != 0);
}

/// u128s_from_felt252 + upcast + div_rem
#[test]
fn bench_u128_approach_512() {
    let x: felt252 = 7777;
    let mut sum: felt252 = 0;
    let mut i: u32 = 0;
    while i != 512 {
        let r: U128AsBounded = upcast(felt252_as_u128(x + SHIFT));
        let (_, r) = bounded_int_div_rem(r, NZ_Q);
        sum = sum + upcast(r);
        i += 1;
    };
    assert!(sum != 0);
}

/// match try_into (downcast) + div_rem
#[test]
fn bench_downcast_approach_512() {
    let x: felt252 = 7777;
    let mut sum: felt252 = 0;
    let mut i: u32 = 0;
    while i != 512 {
        let r: ShiftedT = match (x + SHIFT).try_into() {
            Option::Some(v) => v,
            Option::None => upcast(FALLBACK),
        };
        let (_, r) = bounded_int_div_rem(r, NZ_Q);
        sum = sum + upcast(r);
        i += 1;
    };
    assert!(sum != 0);
}

